def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    prime_cache = {}
    def is_prime(num):
        if num < 2:
            return False
        if num in prime_cache:
            return prime_cache[num]
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                prime_cache[num] = False
                return False
        prime_cache[num] = True
        return True
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else 700 + cap * 0.1
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                decay_factor = np.exp(-a * ratio * 7)
                sin_comp = np.sin(cap * a) + np.cos(a * ratio * 10)
                score += decay_factor * sin_comp * (25 / (a + 2))
            for b in range(1, int(cap) + 1):
                if cap % b == 0:
                    if is_prime(b):
                        score += (b ** 0.5) * 1.5
                    if b % 4 == 3:
                        score += np.log1p(b) * 2
            if cap % 7 == 0:
                score *= 1.12
        elif 0.1 <= ratio < 0.3:
            base_cos = np.cos(ratio * np.pi * 6) * 20
            series_sum = 0
            for c in range(1, 8):
                series_sum += ((-1) ** c) * (ratio ** c) / (c + 1)
            score += base_cos + series_sum * 12
            divisors = [5, 8, 12]
            div_flag = False
            for d in divisors:
                if cap % d == 0:
                    score += d * 1.5
                    div_flag = True
            if div_flag:
                score *= 1.09
            prime_check = is_prime(int(cap))
            if prime_check and ratio > 0.2:
                score += 15
        elif 0.3 <= ratio <= 0.6:
            sine_comp = np.sin(ratio * np.pi * 7) * 18
            factorial_sum = 0
            for e in range(1, 10):
                fact = 1
                for f in range(1, e + 1):
                    fact *= f
                factorial_sum += ((-1) ** e) * (ratio ** e) / fact
            score += sine_comp + factorial_sum * 11
            for g in range(2, int(min(15, cap))):
                if cap % g == 0 and g % 3 == 2:
                    score += np.sqrt(g) * 3.1
            if int(cap) % 6 == 0:
                score *= 0.79
        elif 0.6 < ratio <= 0.9:
            logistic = 40 / (1 + np.exp(-30 * (ratio - 0.78)))
            score += logistic
            for h in range(1, 15):
                if is_prime(h) and h % 4 == 3:
                    score += h * 1.1
            if ratio > 0.85:
                score += (1 - ratio) * 90
            if cap % 4 == 0 and ratio < 0.9:
                score *= 1.25
        elif 0.9 < ratio <= 1.2:
            penalty = 0
            chunk = max(1, int(cap // 4))
            for i in range(1, chunk + 2):
                if cap % i == 0:
                    penalty += i ** 1.9
            fract_part = ratio - int(ratio)
            for j in range(1, 10):
                mod_val = (fract_part * j * 1100) % 11
                penalty += (mod_val / 11) * 6
            score += penalty / (chunk + 3)
            score += (ratio - 1) * (-65)
            if cap % 13 == 0:
                score *= 0.85
            if int(cap) % 17 == 0:
                score += 18
        elif 1.2 < ratio < 2.5:
            complex_sum = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    if k % 3 == 0:
                        complex_sum += np.log1p(k) * 4
                    else:
                        complex_sum += np.sqrt(k) * 2.7
            fract_part = ratio - int(ratio)
            for m in range(1, 15):
                complex_sum += np.sin(fract_part * m * np.pi) * 2.5
            score += complex_sum
            score += (ratio - 1.5) * 78
            if ratio > 2:
                for n in range(1, int(cap // 4) + 2):
                    if n % 5 == 0:
                        score += np.cos(n) * 5.2
        else:
            ultra_sum = 0
            for p in range(1, int(min(25, cap))):
                if cap % p == 0:
                    if p % 2 == 1:
                        ultra_sum += np.exp(-p / 10) * 7
                    else:
                        ultra_sum += np.sqrt(p) * 3.9
            fract = ratio - int(ratio)
            for q in range(1, 20):
                ultra_sum += np.cos(fract * q * np.pi / 2) * 3.3
            score += ultra_sum
            score += (ratio - 3) * 100
            if ratio > 5:
                for r in range(1, int(cap // 5) + 1):
                    if r % 11 == 0 or r % 13 == 0:
                        score += np.sin(r) * 6
        if int(cap) % 7 == 0 and ratio < 2.2:
            score *= 1.1
        if int(cap) % 9 == 0 and ratio > 0.7:
            score *= 0.7
        if ratio > 2.5 and int(cap) % 8 == 0:
            score += 25
        if int(cap) % 16 == 0:
            score *= 0.78
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 450)
    return priorities
